from __future__ import annotations
import copy
from arcgis.auth.tools import LazyLoader
from arcgis.ai._utils import (
    AIUtilsException,
    _get_url,
    _get_gis,
    _handle_ai_response,
    AIUtilsResponse,
)
from typing import Any
from arcgis.auth import EsriSession

_arcgis_gis = LazyLoader("arcgis.gis")


def analyze_image(
    image: str,
    prompt: str | list[str] | list[dict[str, str]],
    to_language: str | None = None,
    from_language: str | None = "en",
    *,
    gis: _arcgis_gis.GIS | None = None,
) -> AIUtilsResponse | AIUtilsException:
    """
    Analyze the image using AI-powered models for object detection, text extraction,
    image description, and segmentation.

    .. note::
        The image must be hosted on an `arcgis.com` domain. Images from other
        domains will not be accepted. Currently supported formats: *JPEG*, *PNG*.

    ===============     ====================================================================
    **Parameter**       **Description**
    ---------------     --------------------------------------------------------------------
    image               Required string. URL of the image (must be hosted on arcgis.com domain).
                        Can also be a Base64 encoded string of the image data, but this is
                        not recommended for large images.
    ---------------     --------------------------------------------------------------------
    prompt              Required string, list of strings, or list of dictionaries. This is
                        the actual prompt or list of prompts describing the analysis to
                        perform.

                        .. code-block:: python

                            # Example formats - Prompt as single string:

                            result = analyze_image(
                                        ...
                                        prompt="List all the colors present in the image.",
                                        ...
                            )

                            # Prompt as list of strings:
                            result = analyze_image(
                                        ...
                                        prompt=[
                                            "Describe the scene in the image.",
                                            "Identify any text in the image."
                                        ],
                                        ...
                            )

                            # Prompt as list of dictionaries:
                            result = analyze_image(
                                        ...
                                        prompt=[
                                            {
                                                "key": "colors_prompt",
                                                "context": "List all the colors present in the image."
                                            },
                                            {
                                                "key": "text_prompt",
                                                "context": "Identify any text in the image."
                                            }
                                        ],
                                        ...
                            )
    ---------------     --------------------------------------------------------------------
    to_language         Optional str. The target language for translation. If not specified,
                        the default is US English ("en"). To see a list of supported
                        languages, use the :attr:`~arcgis.gis.GIS.languages` property of a
                        :class:`~arcgis.gis.GIS` object.
    ---------------     --------------------------------------------------------------------
    from_language       Optional str. The source language. The default is US English ("en").
    ---------------     --------------------------------------------------------------------
    gis                 Optional :class:`~arcgis.gis.GIS`. The connection to the
                        organization that has AI assistants enabled.
    ===============     ====================================================================

    :return:
        An :class:`~arcgis.ai.AIUtilsResponse` or :class:`~arcgis.ai.AIUtilsException`
        containing the analysis results.

    .. code-block:: python

        # Usage Example 1: Using single prompt
        from arcgis.gis import GIS
        from arcgis.ai import analyze_image

        gis = GIS(profile="your_profile")

        image_url = "https://www.arcgis.com/sharing/rest/content/items/12345/info/iteminfo/thumbnail/thumbnail.png"
        prompt = "Describe the scene in the image."

        response = analyze_image(image=image_url, prompt=prompt, gis=gis)

        if isinstance(response, AIUtilsResponse):
            print("Analysis successful!")
            print(response.value)
        elif isinstance(response, AIUtilsException):
            print("Analysis failed!")
            print(response.value)

        # Usage Example 2: Using list of strings for *prompt* argument
        prompts = [
            "Describe the scene in the image.",
            "Identify any text in the image."
        ]

        response = analyze_image(image=image_url, prompt=prompts, gis=gis)

        if isinstance(response, AIUtilsResponse):
            print("Analysis successful!")
            print(response.value)
        elif isinstance(response, AIUtilsException):
            print("Analysis failed!")
            print(response.value)

        # Usage Example 3: Using list of dictionaries for *prompt* argument
        dict_prompts = [
            {"key": "scene_description", "context": "Describe the scene in the image."},
            {"key": "text_identification", "context": "Identify any text in the image."}
        ]

        response = analyze_image(image=image_url, prompt=dict_prompts, gis=gis)

        if isinstance(response, AIUtilsResponse):
            print("Analysis successful!")
            print(response.value)
        elif isinstance(response, AIUtilsException):
            print("Analysis failed!")
            print(response.value)

    """
    # Get GIS instance and service URL
    gis = _get_gis(gis)
    service_url = _get_url(gis, "image_analyze")
    if service_url is None:
        raise ValueError(
            "The image analysis service is not available in your organization."
        )
    session: EsriSession = gis.session

    # Prepare prompt data
    if isinstance(prompt, str):
        prompt_data = [{"key": "unique_string_1", "context": prompt}]
    elif isinstance(prompt, (list, tuple)):
        # Flatten if prompt is a list of dicts (already formatted), else convert each string to dict
        if prompt and all(
            isinstance(t, dict) and "key" in t and "context" in t for t in prompt
        ):
            prompt_data = prompt  # Already in correct format
        else:
            prompt_data = [
                {"key": f"unique_string_{idx}", "context": t}
                for idx, t in enumerate(prompt)
            ]
    if not prompt_data:
        raise ValueError(
            "The prompt parameter must contain at least one prompt and be of type `str`, `list[str]`, or `list[dict[str, str]]`."
        )

    # Prepare request parameters
    params: dict[str, Any] = {
        "input": image,
        "data": prompt_data,
        "inputCulture": from_language,
    }
    if to_language:
        params["outputCulture"] = to_language

    # Prepare headers and make the request
    headers = copy.copy(session.headers)
    headers["x-esri-request-source"] = "ArcGIS-API-For-Python"
    resp = session.post(
        url=service_url,
        json=params,
        headers=headers,
    )

    return _handle_ai_response(resp)
